from typing import List


class Solution:
    def minSplitRangeSum(self, nums: List[int]) -> int:
        # 排序后枚举前缀/后缀切分，极差只由两端点决定
        nums = sorted(nums)
        n = len(nums)
        best = 10**30
        for k in range(n - 1):
            # 左组 [0..k]，右组 [k+1..n-1] 的极差之和
            cur = nums[k] - nums[0] + nums[n - 1] - nums[k + 1]
            if cur < best:
                best = cur
        return best
```

