import java.util.Arrays;

class Solution {
    public long minSplitRangeSum(int[] nums) {
        // 排序后只需考虑连续前缀与后缀的分组
        Arrays.sort(nums);
        int n = nums.length;
        long best = Long.MAX_VALUE;
        for (int k = 0; k < n - 1; k++) {
            // 左极差 nums[k]-nums[0]，右极差 nums[n-1]-nums[k+1]
            long cur = (long) nums[k] - nums[0] + (long) nums[n - 1] - nums[k + 1];
            if (cur < best) {
                best = cur;
            }
        }
        return best;
    }
}
