#include <algorithm>
#include <climits>
#include <vector>
using namespace std;

class Solution {
public:
    long long minSplitRangeSum(vector<int>& nums) {
        // 排序后枚举切分点 k：左组 [0..k]，右组 [k+1..n-1]
        sort(nums.begin(), nums.end());
        int n = static_cast<int>(nums.size());
        long long best = LLONG_MAX;
        for (int k = 0; k < n - 1; ++k) {
            long long cur = static_cast<long long>(nums[k]) - nums[0]
                + static_cast<long long>(nums[n - 1]) - nums[k + 1];
            if (cur < best) {
                best = cur;
            }
        }
        return best;
    }
};
