```c
#include <stdlib.h>

static int cmp(const void* a, const void* b) {
    return *(int*)a - *(int*)b;
}

long long minSplitRangeSum(int* nums, int numsSize) {
    // 排序后枚举前缀 / 后缀切分
    qsort(nums, numsSize, sizeof(int), cmp);
    long long best = (long long)nums[numsSize - 1] - nums[0];
    for (int k = 0; k < numsSize - 1; k++) {
        // 左组极差 nums[k] - nums[0]，右组极差 nums[n-1] - nums[k+1]
        long long cur = (long long)(nums[k] - nums[0])
                      + (long long)(nums[numsSize - 1] - nums[k + 1]);
        if (cur < best) best = cur;
    }
    return best;
}
