var minSplitRangeSum = function(nums) {
    // 排序后枚举前缀 / 后缀切分
    nums.sort((a, b) => a - b);
    let n = nums.length;
    let best = nums[n - 1] - nums[0];
    for (let k = 0; k < n - 1; k++) {
        // 左组极差 nums[k] - nums[0]，右组极差 nums[n-1] - nums[k+1]
        let cur = (nums[k] - nums[0]) + (nums[n - 1] - nums[k + 1]);
        if (cur < best) best = cur;
    }
    return best;
};
